test("does not render the description when missing", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(actionPageUrlPattern, {
    body: {
      ...mockActionPage,
      description: undefined,
    },
  });

  await page.goto("/lead/demo-org/lead-token");

  await expect(page.getByText(descriptionText)).toHaveCount(0);
});

test("redirects when callbackUrl is a valid URL", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  const validCallbackUrl = "/thanks";
  await mockLeadSubmission(mockServerRequest, {
    callbackUrl: validCallbackUrl,
  });

  await page.goto("/lead/demo-org/lead-token");

  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  await page.getByLabel("Phone").fill("5555555555");
  await page.getByLabel("First name").fill("Ada");
  await page.getByLabel("Last name").fill("Lovelace");
  await page.getByRole("combobox", { name: "Address" }).fill("123 Main St");
  await page.getByLabel("City").fill("Austin");
  await page.getByLabel("State").fill("TX");
  await page.getByLabel("Postal code").fill("78701");
  await page.getByLabel("Country").fill("USA");

  // Valid callbackUrl should redirect.
  await expect(page.getByRole("button", { name: "Submit" })).toBeEnabled();
  await page.getByRole("button", { name: "Submit" }).click();
  await page.pause();
  console.log(page.url());
  await expect(page).toHaveURL(new RegExp(`${validCallbackUrl}$`));
});

test("redirects when callbackUrl is invalid", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  await mockLeadSubmission(mockServerRequest, {
    callbackUrl: "//this-is-not-a-valid-url",
  });

  await page.goto("/lead/demo-org/lead-token");

  await page.getByLabel("Email", { exact: true }).fill("test@example.com");
  await page.getByLabel("Phone").fill("5555555555");
  await page.getByLabel("First name").fill("Ada");
  await page.getByLabel("Last name").fill("Lovelace");
  await page.getByRole("combobox", { name: "Address" }).fill("123 Main St");
  await page.getByLabel("City").fill("Austin");
  await page.getByLabel("State").fill("TX");
  await page.getByLabel("Postal code").fill("78701");
  await page.getByLabel("Country").fill("USA");

  // Invalid callbackUrl should not redirect.
  await page.getByRole("button", { name: "Submit" }).click();
  await expect(page).toHaveURL(/\/lead\/demo-org\/lead-token$/);
});

